from lxml import etree


def get_student_info(
    xml_data: str, username: str, password: str
) -> Dict[str, str] | None:
    parser = etree.XMLParser(resolve_entities=False, no_network=True)
    root = etree.fromstring(xml_data.encode() if isinstance(xml_data, str) else xml_data, parser=parser)

    # Use XPath with variables to avoid injection
    result = root.xpath(
        "//student[username=$u and password=$p]",
        u=username,
        p=password,
    )

    if not result:
        return None

    student = result[0]
    info: Dict[str, str] = {}
    for child in student:
        if child.tag is etree.Comment:
            continue
        info[child.tag] = child.text if child.text is not None else ""

    return info

def get_url_for_query(api_url: str, user_id: str) -> str | None:
    if not isinstance(api_url, str) or not isinstance(user_id, str):
        return None

    if not user_id:
        return None

    # Validate user_id: only allow alphanumeric characters to prevent
    # injection, path traversal, or URL manipulation attacks.
    if not user_id.isalnum():
        return None

    base = api_url.rstrip('/')
    return f"{base}/{user_id}"

